export const CONTACT_SIGNATURE =
  "\n\nPortfolio Projects: https://laxman824.github.io/projects\n" +
  "LinkedIn: https://linkedin.com/in/laxman-k-44913a156/\n" +
  "Mobile: +91-9000063740";

// ===== ENGAGEMENT TRACKING (Phase B auto-apply) =====
// Each drafted application gets a random trackId. The email carries a tracked
// "Resume (PDF)" link through the jobhuntTrack Cloud Function, which logs the
// click and 302-redirects to the real CV. The dashboard polls batch stats.
const TRACK_ENDPOINT =
  "https://us-central1-portfolio-142b7.cloudfunctions.net/jobhuntTrack";

// The portfolio-hosted resume. Note: CRA content-hashes this filename — if the
// resume is rebuilt, update it here (or point at a stable copy).
export const DEFAULT_CV_URL =
  "https://laxman824.github.io/static/media/K_Laxman_resume.088e456af6e764b18d05.pdf";

export function makeTrackId() {
  const bytes = new Uint8Array(12);
  (window.crypto || {}).getRandomValues
    ? window.crypto.getRandomValues(bytes)
    : bytes.forEach((_, i) => (bytes[i] = Math.floor(Math.random() * 256)));
  return Array.from(bytes, (b) => b.toString(16).padStart(2, "0")).join("");
}

export function trackedCvLink(trackId) {
  return `${TRACK_ENDPOINT}?a=cv&id=${trackId}`;
}

// Fire-and-forget: drafting must never block on tracking registration.
export function registerTracking({ trackId, appId, cvUrl, job }) {
  return fetch(`${TRACK_ENDPOINT}?a=reg`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      id: trackId,
      appId,
      cvUrl: cvUrl || DEFAULT_CV_URL,
      job: job ? { title: job.title, company: job.company } : null,
    }),
  }).catch(() => {});
}

export async function fetchEngagement(trackIds) {
  const ids = (trackIds || []).filter(Boolean).slice(0, 50);
  if (!ids.length) return {};
  try {
    const res = await fetch(`${TRACK_ENDPOINT}?a=stats&ids=${ids.join(",")}`);
    if (!res.ok) return {};
    const data = await res.json();
    return data.stats || {};
  } catch (e) {
    return {};
  }
}

// AI-assisted recruiter-email suggestions: Gemini knows most companies'
// primary email domain; combine it with the standard HR mailbox patterns.
// These are GUESSES — surfaced with a clear unverified warning. A Hunter.io
// key behind a Function proxy can replace this with verified addresses later.
export async function suggestRecruiterEmails(job) {
  const prompt = `Company: "${job.company}"${
    job.location ? ` (job located in ${job.location})` : ""
  }.

1. What is this company's primary corporate email domain (the part after @ in employee emails)? If it's a well-known company give the real domain; if you are not sure, derive the most likely one from its website domain.
2. List the most likely HR/recruiting mailbox addresses at that domain, best first. Use common patterns: careers@, hr@, talent@, jobs@, recruitment@, hiring@ — but ONLY the 3-4 most plausible for a company of this type.

Return ONLY valid JSON:
{"domain": "example.com", "confidence": "high|medium|low", "emails": ["careers@example.com", "hr@example.com"]}`;

  const parsed = await callAIJson(prompt, 1536);
  if (!parsed?.emails?.length) throw new Error("No suggestions");
  return {
    domain: parsed.domain || "",
    confidence: parsed.confidence || "low",
    emails: parsed.emails.slice(0, 4),
  };
}

// Assisted recruiter-contact discovery: prefilled searches for the company.
// (True enrichment APIs — Apollo/Hunter — can slot in behind this later.)
export function recruiterSearchLinks(job) {
  const company = job?.company || "";
  return {
    linkedin: `https://www.linkedin.com/search/results/people/?keywords=${encodeURIComponent(
      `${company} technical recruiter`
    )}`,
    google: `https://www.google.com/search?q=${encodeURIComponent(
      `"${company}" (recruiter OR "talent acquisition") (email OR contact)`
    )}`,
  };
}

// One silent retry: the LLM fallback chain occasionally returns prose instead
// of JSON on the first call; a retry almost always recovers.
async function callAIJson(prompt, maxTokens) {
  for (let attempt = 0; attempt < 2; attempt++) {
    try {
      const raw = await callAI(prompt, maxTokens);
      const parsed = extractJSON(raw);
      if (parsed) return parsed;
    } catch (e) {
      if (attempt === 1) throw e;
    }
  }
  return null;
}

// Signature incl. the tracked CV link when the application has a trackId.
function buildSignature(trackId) {
  return (
    CONTACT_SIGNATURE +
    (trackId ? `\nResume (PDF): ${trackedCvLink(trackId)}` : "")
  );
}

export async function draftApplication(profile, job) {
  const prompt = `You ARE the candidate below, writing a cold application email to a recruiter in FIRST PERSON ("I", "my"). Never refer to yourself in the third person.

CANDIDATE:
${JSON.stringify(
  {
    name: profile.fullName,
    headline: profile.headline,
    yearsExperience: profile.yearsExperience,
    coreSkills: profile.coreSkills,
    summary: profile.summary,
  },
  null,
  2
)}

MY KEY PROJECTS (quantified evidence — pick what fits THIS job):
${(profile.keyProjects?.length
  ? profile.keyProjects
  : DEFAULT_PROFILE.keyProjects
)
  .map((p, i) => `${i + 1}. ${p}`)
  .join("\n")}

JOB:
Title: ${job.title}
Company: ${job.company}
Location: ${job.location}
${
  job.matchReasons?.length
    ? `Candidate's matched skills: ${job.matchReasons.join(", ")}`
    : ""
}
${
  job.jd
    ? `FULL JOB DESCRIPTION:\n${job.jd.slice(0, 4500)}`
    : "(no job description available — lean on the title and matched skills)"
}

Write the email following these rules:
- FIRST PERSON throughout — you are ${
    profile.fullName
  } applying for your own job.
- Subject: specific and scannable, format like "GenAI engineer (3 yrs, Vertex AI) — <Role>". Max 10 words, never just "<Role> Application".
- Body: 130-180 words, plain text (no markdown), professional but human.
- EVIDENCE IS THE POINT: pick the 1-2 KEY PROJECTS that best match the job description's actual requirements and cite them with their numbers ("80,000+ documents/month", "60% faster"). Explicitly connect each cited project to a specific requirement or responsibility from the JD — show the mapping, don't make me generic.
- If the JD names specific tech I have (e.g. Vertex AI, RAG, LangGraph, Spring Boot), name-check it precisely.
- Structure: 1 line hook tying me to THIS role → 2-3 sentences of project evidence mapped to JD requirements → 1 sentence on why this company → clear low-friction ask (brief call or passing my CV on).
- Mention my CV is attached.
- No clichés ("I hope this finds you well", "passionate", "team player"), no flattery padding, no placeholders like [Name] — if the recruiter's name is unknown, open with "Hi," alone.
- Sign off with my name ONLY. Do NOT include any links, URLs, phone numbers, or contact details — a signature block is appended automatically after your sign-off.

Return ONLY valid JSON:
{"subject": "string", "body": "string"}`;

  // Gemini 2.5 spends "thinking" tokens from the same output budget — a big
  // prompt can starve the JSON (finishReason MAX_TOKENS). Keep this generous.
  const parsed = await callAIJson(prompt, 3072);
  if (!parsed?.subject || !parsed?.body)
    throw new Error("Could not draft the application email");
  return { ...parsed, body: parsed.body.trim() + buildSignature(job.trackId) };
}

export async function draftFollowUp(profile, job) {
  const sentDate = job.dateApplied
    ? new Date(job.dateApplied).toDateString()
    : "recently";
  const prompt = `You ARE the candidate below. Write a short FIRST-PERSON follow-up email for your own job application that has had no response.

CONTEXT:
- Candidate: ${profile.fullName} — ${profile.headline}
- Role: ${job.title} at ${job.company}
- Original application sent: ${sentDate}
${job.draft?.subject ? `- Original subject: ${job.draft.subject}` : ""}

Rules:
- FIRST PERSON ("I", "my") — never refer to yourself in the third person.
- Subject: reply-style, referencing the role. Max 8 words.
- Body: 60-90 words max. Polite, zero pressure, adds ONE new piece of value (a relevant achievement, link, or availability) rather than just "checking in".
- Plain text, no placeholders. Sign off with my name ONLY — no links, URLs, or phone numbers (a signature block is appended automatically).

Return ONLY valid JSON:
{"subject": "string", "body": "string"}`;

  const parsed = await callAIJson(prompt, 2048);
  if (!parsed?.subject || !parsed?.body)
    throw new Error("Could not draft the follow-up");
  return { ...parsed, body: parsed.body.trim() + buildSignature(job.trackId) };
}

// Prefilled Gmail compose window (user reviews + attaches CV + sends from
// their own account). Falls back to mailto: for non-Gmail users.
export function gmailComposeUrl({ to = "", subject = "", body = "" }) {
  const params = new URLSearchParams({
    view: "cm",
    fs: "1",
    to,
    su: subject,
    body,
  });
  return `https://mail.google.com/mail/?${params.toString()}`;
}

export function mailtoUrl({ to = "", subject = "", body = "" }) {
  return `mailto:${encodeURIComponent(to)}?subject=${encodeURIComponent(
    subject
  )}&body=${encodeURIComponent(body)}`;
}

// ===== DIRECT SEND VIA THE USER'S OWN GMAIL (Phase C) =====
// One click after review: OAuth popup (gmail.send scope) → RFC 2822 MIME with
// the resume PDF attached → Gmail API send. The user reviews every draft in
// the modal first; this replaces the copy-into-Gmail hop, not the review.

let gmailToken = null;
let gmailTokenExp = 0;

async function getGmailToken() {
  if (gmailToken && Date.now() < gmailTokenExp) return gmailToken;
  const provider = new GoogleAuthProvider();
  provider.addScope("https://www.googleapis.com/auth/gmail.send");
  // Preselect the account already signed into the site, so sending doesn't
  // accidentally switch the dashboard to a different Google account.
  if (auth.currentUser?.email) {
    provider.setCustomParameters({ login_hint: auth.currentUser.email });
  }
  const result = await signInWithPopup(auth, provider);
  const cred = GoogleAuthProvider.credentialFromResult(result);
  if (!cred?.accessToken)
    throw new Error("Google did not return a Gmail access token");
  gmailToken = cred.accessToken;
  gmailTokenExp = Date.now() + 45 * 60 * 1000; // tokens live ~60 min
  return gmailToken;
}

function toBase64(str) {
  // UTF-8 safe base64
  return btoa(unescape(encodeURIComponent(str)));
}

function arrayBufferToBase64(buf) {
  const bytes = new Uint8Array(buf);
  let binary = "";
  const CHUNK = 0x8000;
  for (let i = 0; i < bytes.length; i += CHUNK) {
    binary += String.fromCharCode.apply(null, bytes.subarray(i, i + CHUNK));
  }
  return btoa(binary);
}

function base64Url(b64) {
  return b64.replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
}

export async function sendViaGmail({ to, subject, body, attachCvUrl }) {
  if (!to || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(to))
    throw new Error("Enter a valid recruiter email first");
  const token = await getGmailToken();

  // Fetch the resume PDF to attach (GitHub Pages serves CORS-open assets).
  let pdfB64 = null;
  if (attachCvUrl) {
    try {
      const res = await fetch(attachCvUrl);
      if (res.ok) pdfB64 = arrayBufferToBase64(await res.arrayBuffer());
    } catch (e) {
      /* send without attachment rather than failing the whole send */
    }
  }

  const boundary = `jh_${Math.random().toString(16).slice(2)}`;
  const subjectEncoded = `=?UTF-8?B?${toBase64(subject)}?=`;

  const lines = [
    `To: ${to}`,
    `Subject: ${subjectEncoded}`,
    "MIME-Version: 1.0",
    `Content-Type: multipart/mixed; boundary="${boundary}"`,
    "",
    `--${boundary}`,
    'Content-Type: text/plain; charset="UTF-8"',
    "Content-Transfer-Encoding: base64",
    "",
    toBase64(body),
  ];
  if (pdfB64) {
    lines.push(
      "",
      `--${boundary}`,
      'Content-Type: application/pdf; name="K_Laxman_Resume.pdf"',
      "Content-Transfer-Encoding: base64",
      'Content-Disposition: attachment; filename="K_Laxman_Resume.pdf"',
      "",
      pdfB64
    );
  }
  lines.push("", `--${boundary}--`);

  // The MIME string is pure ASCII at this point (unicode already base64'd in
  // the parts), so this outer pass is a straightforward ASCII→base64url.
  const raw = base64Url(toBase64(lines.join("\r\n")));

  const res = await fetch(
    "https://gmail.googleapis.com/gmail/v1/users/me/messages/send",
    {
      method: "POST",
      headers: {
        Authorization: `Bearer ${token}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({ raw }),
    }
  );
  if (!res.ok) {
    const err = await res.json().catch(() => ({}));
    if (res.status === 401 || res.status === 403) {
      gmailToken = null; // force re-consent next attempt
      throw new Error(
        `Gmail permission problem (${res.status}) — click Send again and approve the Gmail access popup`
      );
    }
    throw new Error(`Gmail send failed: ${err.error?.message || res.status}`);
  }
  return { sent: true, attached: !!pdfB64 };
}

// Applied N+ days ago, no reply logged, no follow-up sent yet → nudge.
export function needsFollowUp(job, days = 4) {
  if (job.status !== "applied" || !job.dateApplied) return false;
  if (job.followUpSentAt) return false;
  const age = Date.now() - new Date(job.dateApplied).getTime();
  return age > days * 24 * 60 * 60 * 1000;
}

// ===== LOCALSTORAGE PERSISTENCE =====
const JOBS_KEY = "jobhunt.applications.v1";
const PROFILE_KEY = "jobhunt.profile.v1";

export function loadApplications() {
  try {
    const raw = localStorage.getItem(JOBS_KEY);
    if (raw) return JSON.parse(raw);
  } catch (e) {
    /* ignore */
  }
  // First run: seed the pipeline with real jobs in "saved".
  const seeded = SEED_JOBS.map((j) => ({
    ...j,
    status: "saved",
    notes: "",
    dateAdded: new Date().toISOString(),
    dateApplied: null,
  }));
  saveApplications(seeded);
  return seeded;
}

export function saveApplications(apps) {
  try {
    localStorage.setItem(JOBS_KEY, JSON.stringify(apps));
  } catch (e) {
    /* ignore */
  }
}

export function loadProfile() {
  try {
    const raw = localStorage.getItem(PROFILE_KEY);
    if (raw) return JSON.parse(raw);
  } catch (e) {
    /* ignore */
  }
  return DEFAULT_PROFILE;
}

export function saveProfile(profile) {
  try {
    localStorage.setItem(PROFILE_KEY, JSON.stringify(profile));
  } catch (e) {
    /* ignore */
  }
}

// ===== FIRESTORE SYNC (used when the user is logged in) =====
// Single doc per user at jobhunt/{uid}: { applications, profile, updatedAt }.
// localStorage stays the fast, offline source of truth; Firestore is the
// cross-device mirror. Both are written on every save.

export function currentUid() {
  return auth?.currentUser?.uid || null;
}

// Returns { applications, profile } from Firestore, or null if none / not logged in.
export async function fetchRemote() {
  const uid = currentUid();
  if (!uid) return null;
  try {
    const snap = await getDoc(doc(db, "jobhunt", uid));
    if (snap.exists()) return snap.data();
    return null;
  } catch (e) {
    return null;
  }
}

export async function pushRemote({ applications, profile }) {
  const uid = currentUid();
  if (!uid) return;
  try {
    await setDoc(
      doc(db, "jobhunt", uid),
      { applications, profile, updatedAt: Date.now() },
      { merge: true }
    );
  } catch (e) {
    /* offline / rules -> localStorage still holds the data */
  }
}
