// JobHuntDashboard.js
// Phase 1 of the Job-Hunting Copilot: CV parse -> skills profile, and a
// tracking dashboard for job applications (Saved -> Applied -> Interviewing
// -> Offer -> Rejected), each with a match score.
// Fully self-contained; reuses the existing AI endpoint. No edits to UserSpace.js.

import React, { useEffect, useMemo, useState } from "react";
import { onAuthStateChanged } from "firebase/auth";
import { auth } from "../../firebase/config";
import {
  STATUSES,
  parseCV,
  extractPdfText,
  scoreJobMatch,
  searchJobs,
  estimateMatch,
  loadApplications,
  saveApplications,
  loadProfile,
  saveProfile,
  fetchRemote,
  pushRemote,
  draftApplication,
  draftFollowUp,
  gmailComposeUrl,
  mailtoUrl,
  needsFollowUp,
  recruiterSearchLinks,
  getLastAIProvider,
  makeTrackId,
  registerTracking,
  fetchEngagement,
  suggestRecruiterEmails,
  sendViaGmail,
  DEFAULT_CV_URL,
} from "./jobHuntData";
import "./JobHuntDashboard.css";

function ScoreRing({ score }) {
  const color = score >= 80 ? "#4CAF50" : score >= 60 ? "#FF9800" : "#f44336";
  const dash = (score / 100) * 2 * Math.PI * 22;
  return (
    <div className="jh-ring">
      <svg viewBox="0 0 60 60">
        <circle
          cx="30"
          cy="30"
          r="22"
          fill="none"
          stroke="rgba(255,255,255,0.1)"
          strokeWidth="6"
        />
        <circle
          cx="30"
          cy="30"
          r="22"
          fill="none"
          stroke={color}
          strokeWidth="6"
          strokeLinecap="round"
          strokeDasharray={`${dash} 999`}
          transform="rotate(-90 30 30)"
        />
      </svg>
      <span className="jh-ring-val" style={{ color }}>
        {score}
      </span>
    </div>
  );
}

function StatTile({ label, value, accent }) {
  return (
    <div className="jh-stat">
      <div className="jh-stat-val" style={{ color: accent }}>
        {value}
      </div>
      <div className="jh-stat-label">{label}</div>
    </div>
  );
}

export default function JobHuntDashboard({ embedded = false, onTailor }) {
  const [profile, setProfile] = useState(loadProfile());
  const [apps, setApps] = useState([]);
  const [filter, setFilter] = useState("all");
  const [cvBusy, setCvBusy] = useState(false);
  const [cvError, setCvError] = useState("");
  const [rescoringId, setRescoringId] = useState(null);
  const [showProfile, setShowProfile] = useState(false);
  const [synced, setSynced] = useState(false);

  // Live search
  const [query, setQuery] = useState("");
  const [results, setResults] = useState([]);
  const [searching, setSearching] = useState(false);
  const [searchError, setSearchError] = useState("");
  const [searchedOnce, setSearchedOnce] = useState(false);
  const [aiScoring, setAiScoring] = useState(false);
  const [aiProgress, setAiProgress] = useState({ done: 0, total: 0 });

  // Draft-application modal (Phase A auto-apply — human-in-the-loop)
  const [draftJob, setDraftJob] = useState(null); // the application being drafted
  const [draftMode, setDraftMode] = useState("application"); // application | followup
  const [draftTo, setDraftTo] = useState("");
  const [draftSubject, setDraftSubject] = useState("");
  const [draftBody, setDraftBody] = useState("");
  const [draftBusy, setDraftBusy] = useState(false);
  const [draftError, setDraftError] = useState("");
  const [copied, setCopied] = useState(false);
  const [draftProvider, setDraftProvider] = useState("");
  const [draftJd, setDraftJd] = useState(""); // JD context for a sharper draft
  const [showJd, setShowJd] = useState(false);
  const [emailSuggest, setEmailSuggest] = useState(null); // {domain, confidence, emails}
  const [suggestBusy, setSuggestBusy] = useState(false);
  const [sending, setSending] = useState(false);
  const [notice, setNotice] = useState(""); // transient success toast

  // Engagement stats (Phase B): trackId -> {opens, downloads, ...}
  const [engagement, setEngagement] = useState({});

  // Fast path: localStorage is the immediate source of truth.
  useEffect(() => {
    setApps(loadApplications());
  }, []);

  // When auth resolves, pull the Firestore mirror (if any) and reconcile.
  useEffect(() => {
    const unsub = onAuthStateChanged(auth, async (user) => {
      if (!user) {
        setSynced(false);
        return;
      }
      const remote = await fetchRemote();
      if (remote?.applications?.length) {
        setApps(remote.applications);
        saveApplications(remote.applications);
      } else {
        // First login on this account: seed the cloud from local data.
        pushRemote({
          applications: loadApplications(),
          profile: loadProfile(),
        });
      }
      if (remote?.profile) {
        setProfile(remote.profile);
        saveProfile(remote.profile);
      }
      setSynced(true);
    });
    return () => unsub();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const persist = (next) => {
    setApps(next);
    saveApplications(next);
    pushRemote({ applications: next, profile });
  };

  const updateApp = (id, patch) =>
    persist(apps.map((a) => (a.id === id ? { ...a, ...patch } : a)));

  const setStatus = (id, status) =>
    updateApp(id, {
      status,
      dateApplied:
        status === "applied"
          ? apps.find((a) => a.id === id)?.dateApplied ||
            new Date().toISOString()
          : apps.find((a) => a.id === id)?.dateApplied,
    });

  const removeApp = (id) => persist(apps.filter((a) => a.id !== id));

  // ---- Engagement stats (Phase B): poll the tracking function ----
  const trackIdsKey = useMemo(
    () =>
      apps
        .map((a) => a.trackId)
        .filter(Boolean)
        .join(","),
    [apps]
  );

  const refreshEngagement = async () => {
    if (!trackIdsKey) return;
    const stats = await fetchEngagement(trackIdsKey.split(","));
    setEngagement(stats);
  };

  useEffect(() => {
    if (!trackIdsKey) return undefined;
    let alive = true;
    fetchEngagement(trackIdsKey.split(",")).then((stats) => {
      if (alive) setEngagement(stats);
    });
    return () => {
      alive = false;
    };
  }, [trackIdsKey]);

  // ---- Stats ----
  const stats = useMemo(() => {
    const total = apps.length;
    const applied = apps.filter((a) =>
      ["applied", "interviewing", "offer"].includes(a.status)
    ).length;
    const interviews = apps.filter((a) => a.status === "interviewing").length;
    const avg = total
      ? Math.round(apps.reduce((s, a) => s + (a.matchScore || 0), 0) / total)
      : 0;
    const cvViews = apps.reduce(
      (s, a) => s + (engagement[a.trackId]?.downloads || 0),
      0
    );
    return { total, applied, interviews, avg, cvViews };
  }, [apps, engagement]);

  const filtered = useMemo(
    () =>
      (filter === "all" ? apps : apps.filter((a) => a.status === filter)).sort(
        (a, b) => (b.matchScore || 0) - (a.matchScore || 0)
      ),
    [apps, filter]
  );

  // Default the search box to the candidate's top target title.
  useEffect(() => {
    if (!query && profile.preferredTitles?.length) {
      setQuery(profile.preferredTitles[0]);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [profile]);

  const trackedIds = useMemo(() => new Set(apps.map((a) => a.id)), [apps]);

  // ---- Live search ----
  const runSearch = async () => {
    if (!query.trim()) return;
    setSearching(true);
    setSearchError("");
    setSearchedOnce(true);
    try {
      const loc = (profile.preferredLocations || []).find(
        (l) => l && l.toLowerCase() !== "remote"
      );
      const jobs = await searchJobs({
        query: query.trim(),
        location: loc || "",
        country: "in",
        limit: 20,
      });
      const scored = jobs
        .map((j) => {
          const est = estimateMatch(profile, j);
          return {
            ...j,
            matchScore: est.overallMatchScore,
            matchReasons: est.matchedSkills,
            gaps: [],
          };
        })
        .sort((a, b) => b.matchScore - a.matchScore);
      setResults(scored);
      if (scored.length === 0)
        setSearchError("No jobs found — try a broader title.");
    } catch (err) {
      setSearchError(err.message || "Search failed");
    } finally {
      setSearching(false);
    }
  };

  // Batch AI scoring of the visible search results (top 12 to control quota).
  const scoreAllResults = async () => {
    if (!results.length || aiScoring) return;
    setAiScoring(true);
    const top = results.slice(0, 12);
    setAiProgress({ done: 0, total: top.length });
    let updated = [...results];
    for (let i = 0; i < top.length; i++) {
      try {
        const r = await scoreJobMatch(profile, top[i]);
        const idx = updated.findIndex((x) => x.id === top[i].id);
        if (idx > -1) {
          updated[idx] = {
            ...updated[idx],
            matchScore: r.overallMatchScore,
            matchReasons: r.matchedSkills || updated[idx].matchReasons,
            gaps: r.gaps || [],
            aiScored: true,
          };
        }
      } catch (e) {
        /* keep the local estimate on failure */
      }
      setAiProgress({ done: i + 1, total: top.length });
      updated = [...updated].sort((a, b) => b.matchScore - a.matchScore);
      setResults(updated);
    }
    setAiScoring(false);
  };

  const trackJob = (job) => {
    if (trackedIds.has(job.id)) return;
    persist([
      {
        ...job,
        status: "saved",
        notes: "",
        dateAdded: new Date().toISOString(),
        dateApplied: null,
      },
      ...apps,
    ]);
  };

  const applyToJob = (job) => {
    if (job.url) window.open(job.url, "_blank", "noopener,noreferrer");
    setStatus(job.id, "applied");
  };

  // ---- CV upload ----
  const onCvFile = async (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setCvBusy(true);
    setCvError("");
    try {
      let text = "";
      if (file.type === "application/pdf" || file.name.endsWith(".pdf")) {
        text = await extractPdfText(file);
      } else {
        text = await file.text();
      }
      if (!text || text.length < 50)
        throw new Error("Could not read enough text from that file.");
      const parsed = await parseCV(text);
      setProfile(parsed);
      saveProfile(parsed);
      pushRemote({ applications: apps, profile: parsed });
      setShowProfile(true);
    } catch (err) {
      setCvError(err.message || "Failed to parse CV");
    } finally {
      setCvBusy(false);
      e.target.value = "";
    }
  };

  const rescore = async (job) => {
    setRescoringId(job.id);
    try {
      const result = await scoreJobMatch(profile, job);
      updateApp(job.id, {
        matchScore: result.overallMatchScore,
        matchReasons: result.matchedSkills || job.matchReasons,
        gaps: result.gaps || job.gaps,
      });
    } catch (err) {
      /* keep existing score on failure */
    } finally {
      setRescoringId(null);
    }
  };

  const removeSkill = (list, val) => {
    const next = { ...profile, [list]: profile[list].filter((s) => s !== val) };
    setProfile(next);
    saveProfile(next);
    pushRemote({ applications: apps, profile: next });
  };

  // ---- Draft application / follow-up (Phase A auto-apply) ----
  const generateDraft = async (job, mode, jdOverride) => {
    setDraftBusy(true);
    setDraftError("");
    try {
      // Full JD pasted in the modal beats the (often truncated) stored one
      const jd = (jdOverride !== undefined ? jdOverride : draftJd) || job.jd;
      const jobWithJd = { ...job, jd };
      const d =
        mode === "followup"
          ? await draftFollowUp(profile, jobWithJd)
          : await draftApplication(profile, jobWithJd);
      setDraftSubject(d.subject);
      setDraftBody(d.body);
      setDraftProvider(getLastAIProvider());
    } catch (err) {
      setDraftError(err.message || "Drafting failed — try Regenerate.");
    } finally {
      setDraftBusy(false);
    }
  };

  const openDraft = (job, mode = "application") => {
    // Phase B: every drafted application gets a tracking id so the email can
    // carry a tracked "Resume (PDF)" link (click -> logged -> redirect to CV).
    let effectiveJob = job;
    if (!job.trackId) {
      const trackId = makeTrackId();
      effectiveJob = { ...job, trackId };
      updateApp(job.id, { trackId });
      // Refresh stats only AFTER registration lands, else the fetch races the
      // doc creation and the engagement badge stays empty until next reload.
      const allIds = [...apps.map((a) => a.trackId).filter(Boolean), trackId];
      registerTracking({ trackId, appId: job.id, job }).then(() =>
        fetchEngagement(allIds).then(setEngagement)
      );
    }

    setDraftJob(effectiveJob);
    setDraftMode(mode);
    setDraftTo(job.contactEmail || "");
    setDraftError("");
    setCopied(false);
    setEmailSuggest(null);
    setDraftJd(job.jd || "");
    setShowJd(!job.jd); // nudge for JD paste when we have none
    const saved = mode === "followup" ? job.followUpDraft : job.draft;
    if (saved?.subject) {
      // Reopen an existing draft for editing — no AI call needed
      setDraftSubject(saved.subject);
      setDraftBody(saved.body);
    } else {
      setDraftSubject("");
      setDraftBody("");
      generateDraft(effectiveJob, mode, job.jd || "");
    }
  };

  const closeDraft = () => {
    setDraftJob(null);
    setDraftError("");
  };

  // Persist the current modal contents onto the application record.
  // Saving an application draft also advances saved → drafted.
  const persistDraft = (extra = {}) => {
    if (!draftJob) return;
    const stamp = {
      subject: draftSubject,
      body: draftBody,
      updatedAt: Date.now(),
    };
    const jdPatch =
      draftJd && draftJd !== draftJob.jd ? { jd: draftJd.slice(0, 8000) } : {};
    const patch =
      draftMode === "followup"
        ? { followUpDraft: stamp, contactEmail: draftTo, ...jdPatch }
        : {
            draft: stamp,
            contactEmail: draftTo,
            status: draftJob.status === "saved" ? "drafted" : draftJob.status,
            ...jdPatch,
          };
    updateApp(draftJob.id, { ...patch, ...extra });
  };

  const copyDraft = async () => {
    try {
      await navigator.clipboard.writeText(
        `Subject: ${draftSubject}\n\n${draftBody}`
      );
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
      persistDraft();
    } catch (e) {
      setDraftError("Copy failed — select the text manually.");
    }
  };

  const openInGmail = () => {
    persistDraft();
    window.open(
      gmailComposeUrl({ to: draftTo, subject: draftSubject, body: draftBody }),
      "_blank",
      "noopener,noreferrer"
    );
  };

  const openInMailApp = () => {
    persistDraft();
    window.location.href = mailtoUrl({
      to: draftTo,
      subject: draftSubject,
      body: draftBody,
    });
  };

  const markSent = () => {
    if (!draftJob) return;
    if (draftMode === "followup") {
      persistDraft({ followUpSentAt: new Date().toISOString() });
    } else {
      persistDraft({
        status: "applied",
        dateApplied: draftJob.dateApplied || new Date().toISOString(),
      });
    }
    closeDraft();
  };

  // AI-suggested recruiter mailboxes (unverified pattern guesses)
  const suggestEmails = async () => {
    if (!draftJob || suggestBusy) return;
    setSuggestBusy(true);
    setDraftError("");
    try {
      const s = await suggestRecruiterEmails(draftJob);
      setEmailSuggest(s);
    } catch (e) {
      setDraftError(
        "Could not suggest emails — try the LinkedIn/Google links."
      );
    } finally {
      setSuggestBusy(false);
    }
  };

  // Direct send from the user's own Gmail (OAuth popup on first use).
  // Review happened in this modal; success auto-advances the pipeline.
  const sendNow = async () => {
    if (sending || draftBusy) return;
    setSending(true);
    setDraftError("");
    try {
      const result = await sendViaGmail({
        to: draftTo.trim(),
        subject: draftSubject,
        body: draftBody,
        attachCvUrl: DEFAULT_CV_URL,
      });
      if (draftMode === "followup") {
        persistDraft({ followUpSentAt: new Date().toISOString() });
      } else {
        persistDraft({
          status: "applied",
          dateApplied: draftJob.dateApplied || new Date().toISOString(),
          sentVia: "gmail-api",
        });
      }
      closeDraft();
      setNotice(
        `✅ Sent to ${draftTo.trim()}${
          result.attached
            ? " with your resume attached"
            : " (resume attach failed — sent without it)"
        }`
      );
      setTimeout(() => setNotice(""), 6000);
    } catch (e) {
      const msg = /popup-closed|cancelled-popup|popup-blocked/.test(
        e?.message || ""
      )
        ? "Google popup was closed — nothing was sent. Click Send now to retry."
        : e.message || "Send failed — use Open in Gmail instead.";
      setDraftError(msg);
    } finally {
      setSending(false);
    }
  };

  return (
    <div className={`jobhunt-root ${embedded ? "embedded" : ""}`}>
      {/* Header */}
      <div className="jh-header">
        <div>
          <h1>🎯 Job-Hunting Copilot</h1>
          <p className="jh-sub">
            Parse your CV · match real jobs · track every application
            <span className={`jh-sync ${synced ? "on" : ""}`}>
              {synced ? "☁ Synced" : "💾 Local"}
            </span>
          </p>
        </div>
        <div className="jh-stats">
          <StatTile label="Tracked" value={stats.total} accent="#8892ff" />
          <StatTile label="Applied" value={stats.applied} accent="#2196F3" />
          <StatTile
            label="Interviews"
            value={stats.interviews}
            accent="#FF9800"
          />
          <StatTile label="CV Views" value={stats.cvViews} accent="#00BCD4" />
          <StatTile
            label="Avg Match"
            value={`${stats.avg}%`}
            accent="#4CAF50"
          />
        </div>
      </div>

      {/* CV Parser */}
      <div className="jh-cv-panel">
        <div className="jh-cv-head">
          <div>
            <h3>📄 Candidate Profile</h3>
            <span className="jh-cv-name">
              {profile.fullName} — {profile.headline}
            </span>
          </div>
          <div className="jh-cv-actions">
            <label className="jh-btn primary">
              {cvBusy ? "Parsing…" : "Upload CV"}
              <input
                type="file"
                accept=".pdf,.txt,.md"
                onChange={onCvFile}
                disabled={cvBusy}
                hidden
              />
            </label>
            <button
              className="jh-btn ghost"
              onClick={() => setShowProfile((s) => !s)}
            >
              {showProfile ? "Hide skills" : "Show skills"}
            </button>
          </div>
        </div>
        {cvError && <div className="jh-error">{cvError}</div>}
        {showProfile && (
          <div className="jh-profile">
            <div className="jh-skill-group">
              <span className="jh-skill-label">Core skills</span>
              <div className="jh-chips">
                {profile.coreSkills?.map((s) => (
                  <span key={s} className="jh-chip">
                    {s}
                    <button onClick={() => removeSkill("coreSkills", s)}>
                      ×
                    </button>
                  </span>
                ))}
              </div>
            </div>
            <div className="jh-skill-group">
              <span className="jh-skill-label">Tools</span>
              <div className="jh-chips">
                {profile.tools?.map((s) => (
                  <span key={s} className="jh-chip subtle">
                    {s}
                    <button onClick={() => removeSkill("tools", s)}>×</button>
                  </span>
                ))}
              </div>
            </div>
            <div className="jh-skill-group">
              <span className="jh-skill-label">Targeting</span>
              <div className="jh-chips">
                {profile.preferredTitles?.map((s) => (
                  <span key={s} className="jh-chip role">
                    {s}
                  </span>
                ))}
                {profile.preferredLocations?.map((s) => (
                  <span key={s} className="jh-chip loc">
                    📍 {s}
                  </span>
                ))}
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Live search */}
      <div className="jh-search-panel">
        <div className="jh-search-bar">
          <input
            className="jh-search-input"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && runSearch()}
            placeholder="Search live jobs — e.g. Generative AI Engineer"
          />
          <button
            className="jh-btn primary"
            onClick={runSearch}
            disabled={searching || !query.trim()}
          >
            {searching ? "Searching…" : "🔎 Find Jobs"}
          </button>
        </div>
        <div className="jh-search-meta">
          Live jobs via Adzuna (India + remote), with Remotive fallback. Scored
          against your CV.
        </div>
        {searchError && <div className="jh-error">{searchError}</div>}
        {results.length > 0 && (
          <div className="jh-results-toolbar">
            <span className="jh-results-count">
              {results.length} results · scored locally
            </span>
            <button
              className="jh-btn tiny ghost"
              onClick={scoreAllResults}
              disabled={aiScoring}
              title="Re-score the top results with AI for accurate matches"
            >
              {aiScoring
                ? `🤖 Scoring ${aiProgress.done}/${aiProgress.total}…`
                : "🤖 AI-score all"}
            </button>
          </div>
        )}
        {results.length > 0 && (
          <div className="jh-results">
            {results.map((job) => {
              const isTracked = trackedIds.has(job.id);
              return (
                <div className="jh-result" key={job.id}>
                  <ScoreRing score={job.matchScore} />
                  <div className="jh-job-main">
                    <div className="jh-job-top">
                      <a
                        href={job.url}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="jh-job-title"
                      >
                        {job.title}
                      </a>
                      <span className="jh-job-source">{job.source}</span>
                    </div>
                    <div className="jh-job-meta">
                      <strong>{job.company}</strong>
                      <span>· {job.location}</span>
                      {job.jobType && <span>· {job.jobType}</span>}
                    </div>
                    {(job.aiScored || job.matchReasons?.length > 0) && (
                      <div className="jh-tags">
                        {job.aiScored && (
                          <span className="jh-tag ai">🤖 AI-scored</span>
                        )}
                        {(job.matchReasons || []).slice(0, 6).map((r) => (
                          <span key={r} className="jh-tag good">
                            {r}
                          </span>
                        ))}
                      </div>
                    )}
                  </div>
                  <button
                    className={`jh-btn tiny ${isTracked ? "ghost" : "primary"}`}
                    onClick={() => trackJob(job)}
                    disabled={isTracked}
                  >
                    {isTracked ? "✓ Tracked" : "➕ Track"}
                  </button>
                </div>
              );
            })}
          </div>
        )}
        {searchedOnce && !searching && results.length === 0 && !searchError && (
          <div className="jh-empty">No results.</div>
        )}
      </div>

      {notice && <div className="jh-notice">{notice}</div>}

      {/* Pipeline filter */}
      <div className="jh-filters">
        <button
          className={`jh-filter ${filter === "all" ? "active" : ""}`}
          onClick={() => setFilter("all")}
        >
          All <span className="jh-count">{apps.length}</span>
        </button>
        {STATUSES.map((s) => (
          <button
            key={s.id}
            className={`jh-filter ${filter === s.id ? "active" : ""}`}
            onClick={() => setFilter(s.id)}
            style={filter === s.id ? { borderColor: s.color } : {}}
          >
            {s.icon} {s.label}
            <span className="jh-count">
              {apps.filter((a) => a.status === s.id).length}
            </span>
          </button>
        ))}
        {trackIdsKey && (
          <button
            className="jh-filter jh-refresh-engage"
            onClick={refreshEngagement}
            title="Refresh CV-link click stats from the tracking service"
          >
            📊 Refresh engagement
          </button>
        )}
      </div>

      {/* Job cards */}
      <div className="jh-jobs">
        {filtered.length === 0 && (
          <div className="jh-empty">No jobs in this stage yet.</div>
        )}
        {filtered.map((job) => {
          const st = STATUSES.find((s) => s.id === job.status) || STATUSES[0];
          return (
            <div className="jh-job" key={job.id}>
              <ScoreRing score={job.matchScore || 0} />
              <div className="jh-job-main">
                <div className="jh-job-top">
                  <a
                    href={job.url}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="jh-job-title"
                  >
                    {job.title}
                  </a>
                  <span className="jh-job-source">{job.source}</span>
                </div>
                <div className="jh-job-meta">
                  <strong>{job.company}</strong>
                  <span>· {job.location}</span>
                  {job.jobType && <span>· {job.jobType}</span>}
                </div>
                {(job.matchReasons?.length > 0 ||
                  (job.trackId && engagement[job.trackId])) && (
                  <div className="jh-tags">
                    {job.trackId && engagement[job.trackId] && (
                      <span
                        className={`jh-tag engage ${
                          engagement[job.trackId].downloads > 0 ? "hot" : ""
                        }`}
                        title="Tracked resume-link clicks from your application emails"
                      >
                        📄 CV viewed ×{engagement[job.trackId].downloads}
                        {engagement[job.trackId].opens > 0 &&
                          ` · 👁 ${engagement[job.trackId].opens}`}
                      </span>
                    )}
                    {(job.matchReasons || []).slice(0, 5).map((r) => (
                      <span key={r} className="jh-tag good">
                        {r}
                      </span>
                    ))}
                    {job.gaps?.slice(0, 3).map((g) => (
                      <span key={g} className="jh-tag gap">
                        gap: {g}
                      </span>
                    ))}
                  </div>
                )}
              </div>
              <div className="jh-job-actions">
                <select
                  className="jh-status-select"
                  value={job.status}
                  onChange={(e) => setStatus(job.id, e.target.value)}
                  style={{ borderColor: st.color, color: st.color }}
                >
                  {STATUSES.map((s) => (
                    <option key={s.id} value={s.id}>
                      {s.icon} {s.label}
                    </option>
                  ))}
                </select>
                <button
                  className="jh-btn tiny primary"
                  onClick={() => openDraft(job, "application")}
                  title={
                    job.draft
                      ? "Review / edit the drafted application email"
                      : "AI-draft a personalized application email to a recruiter"
                  }
                >
                  {job.draft ? "✉️ Draft ✓" : "✉️ Draft"}
                </button>
                {(needsFollowUp(job) ||
                  (job.followUpDraft && !job.followUpSentAt)) && (
                  <button
                    className="jh-btn tiny followup"
                    onClick={() => openDraft(job, "followup")}
                    title={
                      job.followUpDraft
                        ? "A follow-up draft is waiting for your review"
                        : "No reply yet — draft a short follow-up email"
                    }
                  >
                    {job.followUpDraft
                      ? "⏰ Follow-up ready ✓"
                      : "⏰ Follow up"}
                  </button>
                )}
                <button
                  className="jh-btn tiny"
                  onClick={() => applyToJob(job)}
                  title="Open the official apply page and mark as Applied"
                >
                  Apply ↗
                </button>
                {onTailor ? (
                  <button
                    className="jh-btn tiny"
                    onClick={() => onTailor(job)}
                    title="Send this JD to the Resume-Agent (pre-fills — paste the full JD there, then Analyze)"
                  >
                    ✨ Tailor
                  </button>
                ) : (
                  <a
                    href={`/myspace`}
                    className="jh-btn tiny"
                    title="Open Resume-Agent to tailor for this job"
                  >
                    ✨ Tailor
                  </a>
                )}
                <button
                  className="jh-btn tiny ghost"
                  onClick={() => rescore(job)}
                  disabled={rescoringId === job.id}
                >
                  {rescoringId === job.id ? "…" : "↻ Rescore"}
                </button>
                <button
                  className="jh-btn tiny danger"
                  onClick={() => removeApp(job.id)}
                >
                  ✕
                </button>
              </div>
            </div>
          );
        })}
      </div>

      {/* ===== Draft-application modal (Phase A auto-apply) ===== */}
      {draftJob && (
        <div className="jh-modal-overlay" onClick={closeDraft}>
          <div className="jh-modal" onClick={(e) => e.stopPropagation()}>
            <div className="jh-modal-head">
              <div>
                <h3>
                  {draftMode === "followup"
                    ? "⏰ Follow-up email"
                    : "✉️ Application email"}
                </h3>
                <span className="jh-modal-sub">
                  {draftJob.title} · {draftJob.company}
                </span>
              </div>
              <button className="jh-modal-close" onClick={closeDraft}>
                ✕
              </button>
            </div>

            <label className="jh-field">
              <span>Recruiter / HR email</span>
              <input
                type="email"
                value={draftTo}
                onChange={(e) => setDraftTo(e.target.value)}
                placeholder="e.g. recruiting@company.com — paste from the job post or LinkedIn"
              />
            </label>
            <div className="jh-contact-helpers">
              <span>No contact yet?</span>
              <button
                className="jh-suggest-btn"
                onClick={suggestEmails}
                disabled={suggestBusy}
              >
                {suggestBusy ? "🤖 Guessing…" : "🤖 Suggest emails"}
              </button>
              <a
                href={recruiterSearchLinks(draftJob).linkedin}
                target="_blank"
                rel="noopener noreferrer"
              >
                🔗 LinkedIn recruiters at {draftJob.company} ↗
              </a>
              <a
                href={recruiterSearchLinks(draftJob).google}
                target="_blank"
                rel="noopener noreferrer"
              >
                🔍 Google ↗
              </a>
            </div>
            {emailSuggest && (
              <div className="jh-email-suggest">
                <span className="jh-email-suggest-note">
                  AI pattern guesses for <strong>{emailSuggest.domain}</strong>{" "}
                  ({emailSuggest.confidence} confidence) — unverified, prefer a
                  named recruiter from LinkedIn when you can:
                </span>
                <div className="jh-chips">
                  {emailSuggest.emails.map((em) => (
                    <button
                      key={em}
                      className={`jh-chip ${draftTo === em ? "" : "subtle"}`}
                      onClick={() => setDraftTo(em)}
                    >
                      {em}
                    </button>
                  ))}
                </div>
              </div>
            )}

            <div className="jh-jd-toggle">
              <button
                className="jh-linklike"
                onClick={() => setShowJd((s) => !s)}
              >
                {showJd ? "▾" : "▸"} Job description context{" "}
                {draftJd
                  ? `(${draftJd.length.toLocaleString()} chars)`
                  : "(none — paste the full JD for a much sharper draft)"}
              </button>
            </div>
            {showJd && (
              <label className="jh-field">
                <span>
                  Paste the full JD — the draft will map your projects to its
                  actual requirements
                </span>
                <textarea
                  rows={5}
                  value={draftJd}
                  onChange={(e) => setDraftJd(e.target.value)}
                  placeholder="Paste the complete job description here, then hit Regenerate"
                />
              </label>
            )}

            {draftBusy ? (
              <div className="jh-draft-loading">
                🤖 Writing a personalized{" "}
                {draftMode === "followup" ? "follow-up" : "application"}…
              </div>
            ) : (
              <>
                <label className="jh-field">
                  <span>
                    Subject
                    {draftProvider && (
                      <em className="jh-provider">
                        drafted via {draftProvider}
                      </em>
                    )}
                  </span>
                  <input
                    type="text"
                    value={draftSubject}
                    onChange={(e) => setDraftSubject(e.target.value)}
                  />
                </label>
                <label className="jh-field">
                  <span>Body — edit freely, it's your voice</span>
                  <textarea
                    rows={draftMode === "followup" ? 6 : 10}
                    value={draftBody}
                    onChange={(e) => setDraftBody(e.target.value)}
                  />
                </label>
              </>
            )}

            {draftError && <div className="jh-error">{draftError}</div>}

            <div className="jh-modal-hint">
              <strong>🚀 Send now</strong> emails this from your own Gmail with
              your resume PDF auto-attached (one-time Google permission popup).
              Or use <strong>Open in Gmail</strong> to finish it there manually.
            </div>

            <div className="jh-modal-actions">
              <button
                className="jh-btn ghost"
                onClick={() => generateDraft(draftJob, draftMode)}
                disabled={draftBusy}
              >
                🔁 Regenerate
              </button>
              <button
                className="jh-btn ghost"
                onClick={copyDraft}
                disabled={draftBusy || !draftBody}
              >
                {copied ? "✓ Copied" : "📋 Copy"}
              </button>
              <button
                className="jh-btn ghost"
                onClick={openInMailApp}
                disabled={draftBusy || !draftBody}
                title="Open in your default mail app"
              >
                📮 Mail app
              </button>
              <button
                className="jh-btn ghost"
                onClick={openInGmail}
                disabled={draftBusy || !draftBody}
                title="Open a prefilled Gmail compose window (manual send, attach CV yourself)"
              >
                ✉️ Open in Gmail
              </button>
              <button
                className="jh-btn sent"
                onClick={markSent}
                disabled={draftBusy || !draftBody}
                title={
                  draftMode === "followup"
                    ? "Record that the follow-up went out"
                    : "Record that the application went out (moves to Applied)"
                }
              >
                ✅ I sent it
              </button>
              <button
                className="jh-btn primary"
                onClick={sendNow}
                disabled={sending || draftBusy || !draftBody || !draftTo.trim()}
                title={
                  draftTo.trim()
                    ? "Send this email now from your own Gmail, resume attached"
                    : "Enter a recruiter email first"
                }
              >
                {sending ? "🚀 Sending…" : "🚀 Send now"}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
